import React, { useEffect, useState } from "react";
import Navbar from "../../components/Navbar";
import styles from "./UserPages.module.css";

const ReceiptPage = () => {
  const [receipt, setReceipt] = useState(null);

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("receipt"));
    setReceipt(data);
  }, []);

  if (!receipt) return <p>No receipt found</p>;

  return (
    <>
      <Navbar />

      <div className={styles.receiptContainer}>
        <h1>🧾 Payment Receipt</h1>

        <div className={styles.receiptCard}>
          <p><b>Booking ID:</b> {receipt.bookingId}</p>
          <p><b>Name:</b> {receipt.name}</p>
          <p><b>Email:</b> {receipt.email}</p>
          <p><b>Phone:</b> {receipt.phone}</p>

          <hr />

          <p><b>Package:</b> {receipt.packageName}</p>
          <p><b>Persons:</b> {receipt.persons}</p>
          <p><b>Payment Method:</b> {receipt.paymentMethod}</p>
          <p><b>Date:</b> {receipt.date}</p>

          <hr />

          <h2>✅ Paid: ₹{receipt.totalAmount}</h2>
        </div>
      </div>
    </>
  );
};

export default ReceiptPage;
